   258	export function toUnavailablePublicHotelQuoteProjection(
   259	  hotel: PublicBookabilityHotelProfile,
   260	  query: PublicHotelQuoteQuery,
   261	  now: Date,
   262	): PublicBookabilityQuoteProjection {
