   264	  const { request, reasons } = parsePublicHotelQuoteRequest(hotel, query, now);
   265	  const readModelUnavailableReason: PublicBookabilityUnavailableReason = {
   266	    code: "unavailable_data",
   267	    detail: "Public quote read model is not ready yet.",
   268	  };
   269	  const unavailableReasons = reasons.length > 0 ? reasons : [readModelUnavailableReason];
   270	  const freshness = unavailableQuoteFreshness(generatedAt, unavailableReasons);
   271	
   272	  const projection: PublicBookabilityQuoteProjection = {
   273	    contractVersion: PUBLIC_BOOKABILITY_CONTRACT_VERSION,
   274	    generatedAt,
   275	    publicVisibility: PUBLIC_BOOKABILITY_VISIBILITY,
   276	    request,
   277	    status:
   278	      freshness.status === "stale" &&
   279	      unavailableReasons.every((reason) => reason.code === "stale_data")
   280	        ? "stale"
